-- 1. Landscapers × Web Design
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'landscapers',
  'web-design',
  'Landscaping is a visual trade, and your website needs to sell the transformation before a single spade hits the ground. Homeowners deciding between landscapers do not read paragraphs of text — they scroll through project galleries, looking for evidence that you can turn their tired patio or overgrown garden into something worth showing off. A landscaping website must showcase before-and-after transformations, present seasonal service pages that match what customers are searching for right now, and make it effortless to request a site visit. Generic template sites with stock images of manicured lawns actively undermine credibility, because every potential customer knows those are not your gardens. We build bespoke websites for Kent landscapers that put your real project portfolio front and centre, with design visualisation tools and clear calls to action that convert browsers into booked consultations.',
  'Homeowners spend hours researching landscapers online before making contact, and your website is where that decision is made. Without a professional site featuring genuine project galleries, garden design visualisations, and seasonal service breakdowns, you are losing jobs to competitors who present their work more effectively. A purpose-built landscaping website turns your completed projects into your most powerful sales tool, working around the clock to generate consultation requests even during your busiest season.',
  'We photograph or source your actual completed projects and build immersive portfolio galleries with filtering by project type — patios, planting schemes, water features, full garden redesigns. Seasonal service pages rotate prominence based on the time of year, and every page funnels visitors toward a site visit booking form with calendar integration.',
  '[{"title": "No project portfolio to showcase completed work", "description": "Most landscaper websites either have no gallery at all or display a handful of poorly lit phone photos. Homeowners comparing three or four landscapers will choose the one whose website proves they can deliver quality work through professional before-and-after project imagery."}, {"title": "Generic templates that look identical to competitors", "description": "Template websites with stock photography of perfect lawns immediately signal to customers that this is not a serious operation. When every landscaper in Kent uses the same Wix or Squarespace template, none of them stand out, and homeowners default to choosing on price alone."}, {"title": "No seasonal service pages matching current search intent", "description": "Customers search for ''garden clearance'' in autumn, ''patio laying'' in spring, and ''fence repair'' after winter storms. Without dedicated seasonal service pages, your site misses the specific searches happening right now and loses those jobs to competitors who have them."}]',
  '[{"title": "Immersive before-and-after project galleries", "description": "We build filterable portfolio galleries that let homeowners browse your completed projects by type — patios, planting, water features, driveways, full redesigns. Each project includes before-and-after sliders, scope description, and approximate timelines, giving prospects confidence in your capabilities."}, {"title": "Seasonal service pages with dynamic prominence", "description": "Dedicated pages for spring planting, summer maintenance, autumn clearance, and winter hardscaping rotate in visibility based on the calendar. Each page targets the exact search terms customers use at that time of year, capturing seasonal demand your competitors miss."}, {"title": "Site visit booking with calendar integration", "description": "Every page drives visitors toward a consultation request form connected to your actual availability calendar. Customers select their preferred date and describe their project, and you receive a structured enquiry ready for follow-up — no phone tag, no missed messages."}]',
  '[{"question": "Can you photograph my completed landscaping projects for the website?", "answer": "Yes. We coordinate project photography for completed gardens, patios, and outdoor spaces. We also work with any existing photos you have, professionally editing and presenting them in before-and-after formats that showcase the transformation."}, {"question": "How do seasonal service pages work on a landscaping website?", "answer": "We create dedicated pages for each seasonal service you offer — spring planting, patio installation, autumn clearance, winter maintenance. These pages are optimised for the search terms customers use during each season and are given greater prominence on your homepage as the relevant period approaches."}, {"question": "Will the website work on mobile for customers browsing in their gardens?", "answer": "Absolutely. Many homeowners browse landscaping websites while standing in the garden they want transformed. Every site we build is fully responsive with fast-loading images, touch-friendly galleries, and tap-to-call functionality so they can contact you instantly."}, {"question": "Can customers see estimated costs on the website?", "answer": "We can include indicative price ranges or project-size guides if you prefer, without committing you to fixed quotes. Many landscapers find that showing approximate starting prices for common services like patio laying or turfing reduces tyre-kicker enquiries and attracts serious customers."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 2. Landscapers × SEO
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'landscapers',
  'seo',
  'When a homeowner searches "landscaper near me" or "patio installation Kent," the businesses appearing in the top three Google results capture the vast majority of enquiries. For landscapers, seasonal search patterns create predictable waves of demand — garden design peaks in spring, fence and paving work surges after winter, and maintenance contracts are researched year-round. Yet most landscaping businesses have no SEO strategy, relying entirely on word of mouth while competitors quietly claim the search visibility that drives consistent new work. A landscaping SEO campaign must target service-specific keywords tied to seasonal intent, dominate the Google Map Pack for your service radius, and build content authority around the types of projects you want to win. We build SEO strategies specifically for landscapers that align your search visibility with the seasonal rhythms of outdoor trade work.',
  'Word of mouth alone cannot sustain consistent growth for a landscaping business. Seasonal demand fluctuations mean you need a steady pipeline of new enquiries to fill gaps between referrals. SEO positions your business in front of homeowners actively searching for the services you offer, precisely when they need them. Without deliberate search optimisation, you are invisible to the customers who are ready to spend money on their gardens right now.',
  'We map landscaping search terms against seasonal demand curves — targeting patio and hardscaping keywords as spring approaches, garden maintenance terms in summer, and clearance services in autumn. Google Business Profile optimisation includes project photos categorised by service type, driving Map Pack visibility for your core service area.',
  '[{"title": "Invisible for seasonal landscaping searches", "description": "Landscaping demand follows predictable seasonal patterns, but without SEO targeting spring garden design, summer maintenance, and autumn clearance terms at the right time, your business misses the peak search windows when homeowners are actively looking to hire."}, {"title": "Google Map Pack dominated by competitors with more reviews", "description": "The Map Pack results for landscaping searches are heavily influenced by review quantity and recency. Competitors who actively collect Google reviews after every completed project push your business below the fold, making you invisible to the highest-intent local searchers."}, {"title": "Directory sites outranking your business for your own services", "description": "Checkatrade, Bark, and MyBuilder aggressively target landscaping keywords across Kent. Without a deliberate SEO strategy, your own website is buried beneath these platforms, forcing you to pay commission for leads that should have come to you directly."}]',
  '[{"title": "Seasonal keyword targeting aligned to landscaping demand", "description": "We build content calendars that publish and promote service pages ahead of seasonal demand peaks. Patio installation pages gain authority before spring, garden maintenance content ranks for summer, and clearance service pages are ready for autumn — capturing each wave of search intent."}, {"title": "Review generation programme for Map Pack dominance", "description": "We implement automated review request workflows triggered after project completion. Consistent, recent five-star reviews with project-specific details push your Google Business Profile into the top three Map Pack positions for landscaping searches in your service area."}, {"title": "Service-area pages targeting specific towns and postcodes", "description": "We create dedicated landing pages for each town and postcode area you serve, targeting long-tail searches like ''patio landscaper in Maidstone'' or ''garden design Tonbridge.'' These pages outrank national directories by demonstrating genuine local relevance and service specificity."}]',
  '[{"question": "How long before SEO generates landscaping enquiries?", "answer": "Most landscaping clients see ranking improvements within eight to twelve weeks for targeted service-plus-location terms. Seasonal terms often move faster when we begin optimisation ahead of the demand peak, as competition for upcoming seasonal keywords is lower during the off-season."}, {"question": "Can SEO help during the quieter winter months?", "answer": "Yes. We target winter-specific searches such as fence repair, drainage work, and garden clearance, as well as forward-planning searches from homeowners researching spring projects. This smooths out the seasonal dip and keeps your enquiry pipeline active year-round."}, {"question": "Should I stop advertising on Checkatrade if I invest in SEO?", "answer": "Not immediately. SEO builds compounding visibility over time, so we recommend maintaining directory listings during the first few months. As organic rankings strengthen and direct enquiries increase, you can gradually reduce paid directory spend and keep more profit per job."}, {"question": "Do you optimise for specific landscaping services or just general terms?", "answer": "Both, but service-specific terms convert better. We target individual services like patio installation, garden design, turfing, fencing, and water features with dedicated optimised pages. These specific searches indicate strong buying intent and generate higher-quality enquiries than generic landscaper searches."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
