-- 3. Landscapers × Lead Capture
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'landscapers',
  'lead-capture',
  'Most landscaping websites lose the majority of their visitors without capturing any contact details. A homeowner visits your site, browses your gallery, and then leaves to check two more landscapers — and you never hear from them. Effective lead capture for landscapers means giving visitors a compelling reason to share their details before they leave: a garden project planner, an instant rough estimate calculator, or a downloadable seasonal maintenance guide. These tools transform anonymous browsers into named, contactable prospects with defined project requirements. For a trade where the average job value ranges from hundreds to thousands of pounds, capturing even a handful of additional leads each month represents significant revenue. We build lead capture systems designed specifically for landscaping businesses that convert casual browsers into consultation-ready prospects.',
  'Landscaping projects involve significant consideration time. Homeowners research multiple businesses, compare portfolios, and often delay for weeks before making contact. Without lead capture mechanisms, you lose everyone who does not call or email on their first visit. A structured lead capture system ensures you have their details and project requirements, allowing you to follow up proactively and stay front of mind through the decision period.',
  'We build landscaping-specific lead magnets: garden project planners that ask about garden size, style preferences, and budget range; seasonal maintenance checklists homeowners actually want; and quick-quote forms that collect project details in exchange for an approximate cost range. Every form feeds directly into your CRM or email system.',
  '[{"title": "Website visitors leave without making contact", "description": "The typical landscaping website converts fewer than two percent of visitors into enquiries. The other ninety-eight percent browse your gallery, perhaps compare your work to a competitor, and disappear without leaving any way for you to follow up or remind them you exist."}, {"title": "No way to capture early-stage researchers", "description": "Many homeowners start researching landscapers months before they are ready to commit. Without a lead magnet offering value at this early stage — like a project planning guide or seasonal maintenance tips — you miss the chance to nurture these prospects through to booking."}, {"title": "Enquiry forms collect insufficient project details", "description": "Generic contact forms with just a name, email, and message field give you no qualifying information. You cannot prioritise large patio installation enquiries over simple lawn-mowing requests when both arrive as identical one-line messages."}]',
  '[{"title": "Garden project planner as a lead magnet", "description": "We create an interactive project planner that asks homeowners about their garden size, desired features, preferred style, and indicative budget. In exchange for their email, they receive a personalised project summary — and you receive a fully qualified lead with detailed project requirements."}, {"title": "Quick-quote calculator for common services", "description": "An approximate cost calculator for popular services like patio laying, turfing, or fencing captures leads by offering instant value. Homeowners enter dimensions and materials preferences, receive a rough estimate, and you receive their contact details alongside the exact project specifications."}, {"title": "Seasonal maintenance guide with email nurture sequence", "description": "A downloadable seasonal garden care guide captures email addresses from homeowners not yet ready for a major project. An automated email sequence delivers genuine maintenance tips over the following weeks, keeping your business top of mind until they are ready to commission work."}]',
  '[{"question": "What is a lead magnet for a landscaping business?", "answer": "A lead magnet is a free resource or tool offered in exchange for contact details. For landscapers, effective lead magnets include garden project planners, seasonal maintenance guides, rough cost calculators, and design inspiration lookbooks. They capture the details of visitors who are interested but not yet ready to call."}, {"question": "Will a cost calculator commit me to specific pricing?", "answer": "No. The calculator provides approximate ranges based on typical project sizes and materials. It includes clear disclaimers that final pricing requires a site visit. The purpose is to give homeowners enough information to stay engaged while capturing their project details for your follow-up."}, {"question": "How do captured leads get sent to me?", "answer": "Leads are delivered instantly via email notification with full project details. We can also integrate with CRM systems, Google Sheets, or project management tools. Each lead includes the homeowner''s contact details, project type, garden dimensions, and any other information collected by the form."}, {"question": "How many extra leads can I expect per month?", "answer": "Results depend on your website traffic, but most landscaping clients see a three to five times increase in lead capture rates after implementing project planners and quick-quote tools. For a site receiving 500 monthly visitors, that typically translates to fifteen to twenty-five additional contactable leads per month."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
