-- 4. Landscapers × Business Automation
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'landscapers',
  'business-automation',
  'Running a landscaping business means spending your evenings writing quotes, chasing customers for approvals, sending appointment reminders, and requesting reviews after completed jobs. These repetitive admin tasks eat into the hours you should be spending on site or planning new projects. Business automation for landscapers eliminates the manual follow-up cycle by creating workflows that trigger automatically: a new enquiry receives an instant acknowledgement, a sent quote gets an automated follow-up after forty-eight hours, a completed project triggers a review request, and a seasonal maintenance reminder goes out before each customer''s garden needs attention. These are not complex enterprise systems — they are practical, trade-focused automations that save landscapers hours every week and ensure no lead, quote, or follow-up opportunity falls through the cracks.',
  'Landscapers lose thousands of pounds in revenue annually to forgotten quote follow-ups and missed review opportunities. When you are on site five days a week, administrative tasks get pushed to evenings and weekends, and things inevitably slip. Automation ensures every enquiry gets an instant response, every quote gets followed up, every completed job generates a review request, and every past customer receives seasonal reminders. It is the difference between a busy tradesperson and a professionally run business.',
  'We build automations around the landscaping workflow: enquiry acknowledgement, quote generation prompts, follow-up sequences for unanswered quotes, booking confirmations with weather-contingency messaging, post-completion review requests, and seasonal maintenance reminders to past customers for recurring revenue.',
  '[{"title": "Quotes sent but never followed up", "description": "Landscapers typically send quotes after a site visit and then wait for the customer to respond. Without systematic follow-up, a significant percentage of viable quotes go cold. Customers who were genuinely interested simply chose the competitor who followed up first."}, {"title": "No system for generating reviews after completed work", "description": "Landscaping projects produce visually impressive results that photograph well and generate enthusiastic reviews — but only if you ask. Without automated review requests sent at the moment of peak satisfaction, completed projects rarely translate into the Google reviews that drive future enquiries."}, {"title": "Past customers forgotten until they call someone else", "description": "A customer who had their garden landscaped two years ago is a prime candidate for maintenance, seasonal planting, or new feature additions. Without automated seasonal reminders, these past customers forget about you and search Google when they need further work — often finding a competitor."}]',
  '[{"title": "Automated quote follow-up sequences", "description": "When you send a quote, an automated sequence sends a follow-up after forty-eight hours, a gentle reminder after one week, and a final check-in after two weeks. Each message is personalised with the customer''s project details, dramatically increasing your quote-to-job conversion rate."}, {"title": "Post-completion review and referral requests", "description": "Automated review requests trigger two days after project completion, when customer satisfaction is highest. The message includes a direct link to your Google Business Profile and a simple referral prompt, systematically building the review count that drives your search visibility."}, {"title": "Seasonal maintenance reminders to past customers", "description": "Automated campaigns contact past customers before each season with relevant maintenance offers — spring planting preparation, summer lawn care packages, autumn clearance, and winter protection. These reminders generate recurring revenue from your existing customer base with zero manual effort."}]',
  '[{"question": "What landscaping tasks can be automated?", "answer": "The most impactful automations for landscapers are enquiry acknowledgements, quote follow-ups, booking confirmations, post-completion review requests, and seasonal maintenance reminders to past customers. We can also automate appointment reminders, weather delay notifications, and annual check-in messages."}, {"question": "Will automated messages feel impersonal to my customers?", "answer": "No. Every message is personalised with the customer''s name, project details, and specific service information. The tone matches your brand voice, and messages are timed to feel natural rather than robotic. Customers experience faster, more professional communication — not cold automation."}, {"question": "How does weather-contingency messaging work?", "answer": "When weather is likely to affect scheduled outdoor work, automated messages notify affected customers about potential delays, offer rescheduling options, and confirm revised dates once conditions improve. This reduces no-show frustrations and demonstrates professional communication."}, {"question": "Can automations connect to the tools I already use?", "answer": "Yes. We integrate with common tools landscapers use including Google Calendar, QuickBooks, Xero, and email platforms. If you track jobs in a spreadsheet, we can build automations around that too. The goal is to enhance your existing workflow, not replace it entirely."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
