-- 5. Landscapers × Branding
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'landscapers',
  'branding',
  'Your landscaping brand is judged long before anyone visits your website. It starts with the van parked on a residential street, the business card left after a site visit, the logo on your quote template, and the workwear your team wears on site. In a trade where customers invite you onto their property and trust you with thousands of pounds of work, visual professionalism signals reliability. Yet most landscapers operate with a logo designed by a mate, inconsistent colours across their van, website, and uniforms, and no cohesive brand identity whatsoever. A properly designed landscaping brand draws on nature-inspired aesthetics — earthy tones, organic shapes, botanical elements — while projecting the commercial professionalism that justifies premium pricing. We create complete brand identities for landscapers that look exceptional on van livery, workwear, project proposals, and every customer touchpoint.',
  'Landscaping is a competitive market where customers often choose based on perceived professionalism rather than actual skill differences. A cohesive brand identity — consistent across your van, website, uniforms, quotes, and business cards — immediately elevates your business above competitors running mismatched visuals. Strong branding also justifies premium pricing by positioning you as an established, professional operation rather than a sole trader with a mower.',
  'We design landscaping brands rooted in nature-inspired palettes and organic design language — earthy greens, warm stone tones, botanical line work — that feel authentic to the trade without looking amateurish. Every brand system is tested across van livery mockups, workwear embroidery, and printed proposal templates before finalisation.',
  '[{"title": "Logo designed years ago with no brand system behind it", "description": "Many landscapers have a logo created cheaply when they first started but no consistent colours, fonts, or visual style applied across their van, website, quotes, and uniforms. This inconsistency makes the business look disorganised and undermines customer confidence during the sales process."}, {"title": "Van livery that fails to generate enquiries", "description": "A landscaping van parked on a residential street is a mobile billboard seen by every neighbour. Poor van design with cluttered text, illegible phone numbers, or cheap vinyl fails to generate the kerb-side enquiries that a well-branded vehicle consistently produces."}, {"title": "Branding does not justify premium pricing", "description": "Landscapers trying to move into higher-value garden design and hardscaping projects need branding that matches the investment their clients are making. A hand-drawn logo and inconsistent visual identity make it difficult to present proposals for projects costing thousands of pounds."}]',
  '[{"title": "Nature-inspired brand identity system", "description": "We design complete brand identities drawing on botanical illustration, earthy colour palettes, and organic typography that feel authentically connected to the landscaping trade. The result is a sophisticated visual identity that works across every format from social media avatars to A-board signage."}, {"title": "Van livery design optimised for residential streets", "description": "Your van is your most visible marketing asset. We design livery with bold, clean branding that is legible from across a street, includes a memorable phone number and website, and creates the professional impression that prompts neighbours to note down your details while you work on their street."}, {"title": "Branded proposal templates for premium projects", "description": "We design professional quote and proposal templates featuring your brand identity, project visualisations, and structured pricing breakdowns. These documents elevate the sales process and justify premium pricing by presenting your business as an established, design-led operation."}]',
  '[{"question": "What should a landscaping brand look like?", "answer": "The most effective landscaping brands use nature-inspired colour palettes — deep greens, warm earth tones, stone greys — combined with clean modern typography and subtle botanical elements. The brand should feel premium and professional while remaining authentic to outdoor trade work."}, {"question": "Do you design van livery for landscapers?", "answer": "Yes. Van livery design is a core part of our landscaping branding packages. We create wrap or vinyl cut designs optimised for your specific vehicle type, ensuring your branding is legible from distance, memorable to passers-by, and consistent with your website and printed materials."}, {"question": "Can branding really help me charge higher prices?", "answer": "Absolutely. Customers use visual cues to assess the quality and professionalism of a business before they ever speak to you. Consistent, high-quality branding across your van, website, quotes, and uniforms positions you as a premium operator, making customers more comfortable with higher pricing."}, {"question": "How long does a full landscaping rebrand take?", "answer": "A complete brand identity including logo, colour system, typography, van livery design, workwear specifications, and branded templates typically takes three to four weeks from initial brief to final delivery. We present concepts after week one and refine based on your feedback."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
