-- 6. Landscapers × Social Media Setup
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'landscapers',
  'social-media-setup',
  'Landscaping is one of the most visually rewarding trades on social media. Before-and-after garden transformations, timelapse project videos, and seasonal planting content generate genuine engagement and enquiries on platforms like Instagram and Facebook. Yet most landscapers either have no social media presence or have abandoned accounts with sporadic posts and no consistent branding. Setting up social media properly for a landscaping business means creating professionally branded profiles, establishing content categories that showcase your work effectively, and building a posting framework you can actually maintain alongside running a busy outdoor trade. A well-structured Instagram grid of completed projects becomes a living portfolio that customers browse before making contact. We set up and optimise social media profiles for landscapers with branded templates, content plans, and posting systems designed for tradespeople who work with their hands, not their phones.',
  'Homeowners increasingly check social media before hiring a landscaper, using Instagram and Facebook as visual portfolios. A professional social presence with consistent project photography builds trust and demonstrates active, ongoing work. Without it, potential customers question whether you are still trading or capable of the quality they expect. Social media also drives referrals when satisfied customers share your posts with neighbours considering similar work.',
  'We set up landscaping social accounts with project showcase templates, before-and-after post formats, and seasonal content calendars. Photo capture guidelines ensure your team can document projects on-site with minimal disruption, and branded story templates let you share work-in-progress updates effortlessly.',
  '[{"title": "No social media presence despite visually stunning work", "description": "Landscapers create dramatic visual transformations every week but rarely document them for social media. Without a social presence, these powerful marketing assets go completely to waste while competitors with inferior work but better social skills attract more enquiries."}, {"title": "Abandoned or inconsistent social accounts", "description": "Many landscapers created Facebook or Instagram accounts but stopped posting after a few weeks. Dormant accounts with posts from months ago look worse than having no social presence at all — customers assume the business is inactive or struggling for work."}, {"title": "No time or knowledge to manage social media", "description": "Landscapers work physically demanding outdoor schedules with little energy left for content creation in the evenings. Without simple systems and templates that make posting quick and effortless, social media becomes an unsustainable burden that gets abandoned."}]',
  '[{"title": "Professionally branded social profiles", "description": "We set up and optimise your Instagram, Facebook, and Google Business profiles with consistent branding, compelling bios highlighting your specialisms, and organised highlights or albums showcasing your best project categories — from patios and planting to water features and full garden redesigns."}, {"title": "Project documentation system for on-site capture", "description": "We provide your team with simple photo and video capture guidelines: specific angles for before shots, progress documentation points, and final reveal framing. A shared folder or app makes uploading effortless, giving you a steady stream of content without disrupting your work schedule."}, {"title": "Content calendar with seasonal posting framework", "description": "A twelve-month content calendar maps post types to seasons: spring transformation reveals, summer maintenance tips, autumn planting guides, and winter planning content. Branded templates for each post type mean creating content takes minutes rather than hours."}]',
  '[{"question": "Which social media platforms work best for landscapers?", "answer": "Instagram is the strongest platform for landscapers due to its visual focus — before-and-after grids and reels generate excellent engagement. Facebook remains important for local community groups and older demographics. We set up both platforms with consistent branding and a content strategy tailored to each."}, {"question": "How often should a landscaper post on social media?", "answer": "Three to four posts per week is ideal, but consistency matters more than frequency. We design a system where two project showcase posts and one or two tips or behind-the-scenes posts per week is achievable alongside a full working schedule."}, {"question": "Can I manage social media myself after setup?", "answer": "Yes. Our setup includes branded templates, a content calendar, and photo capture guidelines specifically designed for tradespeople. We train you or a team member to create and schedule posts efficiently. Most landscapers find they can maintain their social presence in under thirty minutes per week."}, {"question": "Do before-and-after posts actually generate enquiries?", "answer": "Before-and-after garden transformations are among the highest-engagement content types on Instagram and Facebook. They demonstrate your capability visually, generate shares from satisfied customers to their friends and neighbours, and create a portfolio effect that builds trust with potential clients browsing your profile."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
