-- 7. Landscapers × Digital Marketing
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'landscapers',
  'digital-marketing',
  'Digital marketing for landscapers requires a fundamentally different approach from other trades because demand is intensely seasonal and project values vary enormously. A Facebook ad campaign that works brilliantly for patio installations in March will waste budget promoting the same service in November. An effective landscaping digital marketing strategy aligns ad spend, content promotion, and email campaigns with the seasonal rhythms of outdoor work — pushing garden design and hardscaping when homeowners are planning, promoting maintenance packages during summer, and targeting clearance and preparation services through autumn and winter. It also segments your audience by project value, ensuring premium garden design clients see different messaging than customers seeking basic lawn care. We build and manage digital marketing campaigns for landscapers that maximise return by matching the right message to the right audience at the right time of year.',
  'Word of mouth and organic search alone cannot provide the consistent, predictable enquiry flow a landscaping business needs to grow. Digital marketing puts your services in front of homeowners actively considering outdoor projects, at precisely the moment their intent is highest. Seasonal paid campaigns fill pipeline gaps during slower periods, retargeting keeps your business visible to researchers who are not yet ready to commit, and email marketing to past customers generates repeat business without acquisition costs.',
  'We run landscaping campaigns on a seasonal calendar: spring and early summer budgets weighted toward garden design, patio, and planting services; late summer promoting maintenance contracts; autumn driving clearance bookings. Ad creative uses your real project photography, and audience targeting focuses on homeowner demographics within your service radius.',
  '[{"title": "Ad budget wasted on poorly timed campaigns", "description": "Landscapers running the same Google or Facebook ads year-round burn budget promoting services when demand is low. Patio installation ads in December and garden clearance ads in June generate clicks from unready prospects who never convert, draining your marketing budget without delivering jobs."}, {"title": "No strategy to fill seasonal demand gaps", "description": "Most landscapers are overwhelmed with work from April through September but struggle through quieter winter months. Without targeted digital marketing promoting winter-appropriate services — drainage, fencing, hard landscaping, garden clearance — these revenue gaps persist year after year."}, {"title": "Generic ad messaging that fails to differentiate", "description": "Landscaping ads that say ''quality landscaping services'' with a stock image of a green lawn look identical to every competitor. Without compelling creative featuring real project transformations and specific service messaging, your ads fail to stand out in crowded social media feeds."}]',
  '[{"title": "Seasonal campaign calendar maximising ROI", "description": "We plan and execute digital marketing campaigns on a twelve-month calendar aligned to landscaping demand patterns. Budget allocation shifts monthly — heavier spend during peak planning periods, targeted niche campaigns during quieter months — ensuring every pound works hardest when customer intent is highest."}, {"title": "Real project creative that stops the scroll", "description": "Ad campaigns feature your actual completed projects — dramatic before-and-after transformations, timelapse videos, and aerial garden photography. Real work outperforms stock imagery by significant margins in click-through and enquiry conversion rates for landscaping businesses."}, {"title": "Retargeting campaigns for long-consideration projects", "description": "Homeowners researching major garden projects take weeks or months to decide. Our retargeting campaigns keep your business visible throughout this consideration period, showing relevant project examples and testimonials to website visitors who did not enquire on their first visit."}]',
  '[{"question": "How much should a landscaper spend on digital marketing?", "answer": "Most landscaping businesses see strong returns from an initial monthly budget of three hundred to eight hundred pounds, depending on service area size and target project values. We recommend starting conservatively, proving ROI on your highest-margin services, and scaling spend based on measurable results."}, {"question": "Which platforms work best for landscaping advertising?", "answer": "Facebook and Instagram are typically the highest-performing platforms for landscapers because visual project content drives strong engagement. Google Ads captures high-intent searches for specific services. We usually recommend a combination, with budget split adjusted seasonally based on performance."}, {"question": "Can digital marketing help during the quieter winter months?", "answer": "Absolutely. Targeted campaigns promoting winter-appropriate services — hard landscaping, drainage, fencing, garden clearance, and early spring planning consultations — generate work during traditionally slow periods. Many of our landscaping clients now maintain steady enquiry flow year-round through seasonal campaign planning."}, {"question": "How do you measure return on landscaping marketing spend?", "answer": "We track every enquiry back to its source: which ad, which platform, which campaign generated each lead. Monthly reports show cost per enquiry, cost per booked job, and return on ad spend. You see exactly how much revenue your marketing investment produces each month."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 8. Landscapers × Workwear & Print
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'landscapers',
  'workwear-print',
  'Landscapers work in full public view on residential streets, and every job is an opportunity to generate the next one. Branded workwear, vehicle signage, and printed leave-behind materials turn every project into a marketing event. When your team is working on a front garden in a residential estate, every passing neighbour and dog walker sees your brand. Professional workwear signals quality and trustworthiness — critical when you are working on someone''s property — while well-designed business cards and project postcards left with nearby homes convert that visibility into enquiries. Yet most landscaping teams work in unmarked clothes, drive partially branded vans, and leave nothing behind for curious neighbours to find. We provide complete branded workwear, van livery installation, printed marketing materials, and leave-behind cards designed specifically for landscaping businesses to maximise every job''s marketing potential.',
  'Every landscaping job is a public demonstration of your work happening in real time on a visible residential street. Branded workwear, vehicle signage, and printed materials ensure that this natural advertising generates maximum return. Professional presentation also builds customer confidence — homeowners feel more comfortable with a uniformed team on their property, and neighbours are more likely to approach a clearly identified business about their own garden.',
  'We supply durable outdoor workwear — embroidered polos, softshell jackets, and high-vis options — designed to withstand landscaping conditions while maintaining brand consistency. Printed materials include door-drop postcards with before-and-after project images for neighbouring properties and appointment cards for follow-up visits.',
  '[{"title": "Team working on residential streets with no branding visible", "description": "A landscaping crew working on a front garden is seen by dozens of neighbours daily. Without branded workwear and clear vehicle signage, this free marketing exposure is entirely wasted. Neighbours who might have enquired have no idea who you are or how to contact you."}, {"title": "Cheap workwear that degrades after weeks of outdoor work", "description": "Landscaping is tough on clothing — mud, thorns, rain, and constant physical movement destroy low-quality embroidered polos and printed t-shirts within weeks. Faded, torn branded workwear looks worse than no branding at all, actively damaging your professional image."}, {"title": "No leave-behind materials for neighbouring properties", "description": "After completing a garden transformation, most landscapers pack up and leave without any marketing materials for the surrounding homes. Neighbours who admired the work have no card, flyer, or postcard to prompt them into making contact about their own garden."}]',
  '[{"title": "Durable outdoor-grade branded workwear", "description": "We supply landscaping-appropriate workwear — reinforced embroidered polos, waterproof softshell jackets, branded beanies, and high-vis options — made from materials that withstand outdoor trade conditions. Embroidery and print methods are chosen for durability through repeated washing and daily wear."}, {"title": "Neighbour door-drop postcards with project photography", "description": "After each project, branded postcards featuring before-and-after photographs of the completed garden are dropped through letterboxes on the surrounding streets. Each card includes a compelling introductory offer and your contact details, converting nearby visibility into direct enquiries."}, {"title": "Vehicle signage designed for residential street visibility", "description": "Van wraps and magnetic signage designed for maximum legibility from across a residential street. Bold branding, a memorable phone number, and your website address ensure that every minute your van is parked outside a job site generates potential customer awareness and contact."}]',
  '[{"question": "What workwear is best for landscaping teams?", "answer": "We recommend embroidered polo shirts for warm weather, branded softshell jackets for cooler conditions, and embroidered beanies for winter. All items are selected for durability in outdoor conditions. We also offer high-visibility options for roadside and commercial site work."}, {"question": "How do door-drop postcards work after a landscaping job?", "answer": "After completing a project, you or your team distribute branded postcards to nearby homes — typically twenty to fifty properties on the surrounding streets. Each postcard features before-and-after images of the completed work, your contact details, and an introductory offer. This consistently generates one to three enquiries per drop for our landscaping clients."}, {"question": "Can you design van wraps for different vehicle types?", "answer": "Yes. We design livery for vans, pickup trucks, and trailers commonly used by landscaping businesses. Each design is created for your specific vehicle dimensions and optimised for visibility when the vehicle is parked on a residential street during jobs."}, {"question": "How quickly can branded workwear be produced?", "answer": "Standard embroidered workwear orders are completed within seven to ten working days. Rush orders for smaller quantities can often be turned around in five days. We hold stock of core garments in common sizes to ensure fast turnaround for landscaping teams needing to kit out quickly."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 9. Landscapers × AI Chatbots
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'landscapers',
  'ai-chatbots',
  'Landscaping enquiries arrive at unpredictable times — a homeowner admiring their neighbour''s new patio at the weekend, someone researching garden redesigns on a weekday evening, or a property manager needing emergency tree work at short notice. When these potential customers visit your website and find no one available to respond, most leave and contact the next landscaper on their list. An AI chatbot built for landscaping businesses handles these conversations intelligently: qualifying the project type and scope, collecting property details and access requirements, providing approximate timelines for common services, and booking site visit consultations directly into your calendar. It understands the difference between a customer wanting a full garden redesign and someone needing a simple hedge trim, and responds appropriately to each. We build AI chatbots specifically trained on landscaping services that capture and qualify leads twenty-four hours a day without you lifting a finger.',
  'Landscapers spend their working hours on-site with no opportunity to answer phones or respond to website enquiries. By the time you check messages in the evening, motivated prospects have already contacted and potentially booked with a competitor. An AI chatbot engages every visitor instantly, qualifies their project requirements, and books consultations — ensuring you never lose a lead to slow response times while you are busy creating gardens.',
  'Our landscaping chatbots are trained on your specific service offerings, typical project timelines, and service area. They ask intelligent qualifying questions — garden size, project type, access requirements, preferred timing — and distinguish between high-value design projects and routine maintenance requests, prioritising accordingly.',
  '[{"title": "Enquiries lost while working on-site all day", "description": "Landscapers cannot answer phones or respond to web enquiries while operating machinery, laying patios, or managing planting projects. By evening, motivated prospects have already contacted two or three competitors and often committed to whichever business responded first."}, {"title": "No qualification of enquiries before site visits", "description": "Without pre-qualification, landscapers waste hours driving to site visits for projects that turn out to be far below their minimum job value, in areas outside their service radius, or for customers with unrealistic budget expectations. Each wasted visit costs time and fuel."}, {"title": "Weekend and evening enquiries going completely unanswered", "description": "Homeowners frequently research landscapers on Saturday mornings while looking at their garden or on weekday evenings after work. These peak research periods are outside business hours, meaning the highest-intent enquiries receive the slowest responses."}]',
  '[{"title": "Instant engagement with every website visitor", "description": "Your AI chatbot greets every visitor within seconds, asks about their project requirements, and guides them through a conversational qualification process. Whether they visit at midday on Tuesday or ten o''clock on Saturday evening, they receive an immediate, helpful response that keeps them on your site."}, {"title": "Intelligent project qualification and prioritisation", "description": "The chatbot asks targeted questions about garden size, desired features, timeline, and budget range. It distinguishes between a full garden redesign worth thousands and a simple lawn-mowing enquiry, flagging high-value projects for immediate follow-up while routing routine requests appropriately."}, {"title": "Automated site visit booking with calendar integration", "description": "Qualified prospects can book a site visit consultation directly through the chatbot, selecting from your available time slots. You receive a detailed brief — project type, garden dimensions, access notes, and customer expectations — before you arrive, making every consultation more productive."}]',
  '[{"question": "Can an AI chatbot understand different landscaping project types?", "answer": "Yes. We train the chatbot on your full service range — garden design, patio installation, planting schemes, fencing, water features, maintenance contracts, and any specialist services you offer. It asks relevant follow-up questions based on the project type identified and provides appropriate information for each."}, {"question": "What happens when the chatbot cannot answer a question?", "answer": "When the chatbot encounters a question outside its training, it acknowledges the query, captures the customer''s contact details and specific question, and notifies you for a personal follow-up. No visitor is left without a response, and complex enquiries are escalated appropriately."}, {"question": "Will customers know they are talking to a chatbot?", "answer": "The chatbot is transparent about being an AI assistant for your business. In practice, customers appreciate the instant response and structured qualification process. Many prefer it to leaving a voicemail, as they can describe their project in detail and receive helpful information immediately."}, {"question": "Can the chatbot provide rough cost estimates for landscaping work?", "answer": "If you wish, the chatbot can share indicative price ranges for common services like turfing per square metre, standard patio sizes, or fencing per metre run. These are presented as approximate guides with a clear note that a site visit is needed for accurate quotation."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 10. Landscapers × AI Content
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'landscapers',
  'ai-content',
  'Content marketing for landscapers means publishing the kind of expertise that homeowners search for before hiring: seasonal planting guides, patio material comparisons, garden design inspiration, drainage solutions, and maintenance advice. This content builds search visibility, demonstrates authority, and pre-sells your expertise to prospects who are researching before they commit. But writing blog posts, service descriptions, and social captions is the last thing a landscaper has time for after a physical day on-site. AI-powered content creation solves this by generating expert-level landscaping content calibrated to your services, service area, and the seasonal search patterns that drive gardening decisions. Every piece is grounded in genuine horticultural and trade knowledge, optimised for the search terms homeowners actually use, and structured to drive consultation bookings. We set up AI content systems for landscapers that produce a consistent stream of authoritative, SEO-optimised content without requiring you to write a single word.',
  'Landscaping customers research extensively before committing to projects costing hundreds or thousands of pounds. Businesses that publish helpful content — planting guides, material comparisons, design tips — build trust and capture search traffic from these research queries. Without regular content, your website remains static while competitors who publish consistently accumulate search authority and attract the customers doing their homework.',
  'Our AI content system is trained on horticultural knowledge, landscaping trade practices, and your specific services. It produces seasonal blog posts, service page content, and social media captions that reference real plants, materials, techniques, and Kent-specific growing conditions — not generic gardening fluff.',
  '[{"title": "No time to write content after physically demanding days", "description": "Landscapers finish work exhausted from outdoor manual labour and have zero energy for writing blog posts about patio materials or planting schemes. Content creation gets perpetually postponed, leaving the website static and invisible for the dozens of informational searches potential customers make before hiring."}, {"title": "Website content is thin and generic", "description": "Most landscaping websites have brief service descriptions that say little more than ''we do patios, planting, and fencing.'' Without detailed, expert content covering each service, specific materials, design approaches, and project processes, the site fails to demonstrate the expertise that justifies premium pricing."}, {"title": "Competitors publishing content are gaining search advantage", "description": "Landscaping businesses that regularly publish guides, case studies, and seasonal advice accumulate search authority month by month. Without matching this content output, your site falls progressively further behind in rankings for the informational and commercial search terms that drive landscaping enquiries."}]',
  '[{"title": "Seasonal content calendar with automated production", "description": "We create a twelve-month content calendar aligned to landscaping search trends: spring garden design inspiration, summer maintenance guides, autumn planting advice, and winter hardscaping features. AI generates each piece with genuine horticultural accuracy, ready for your review and publication."}, {"title": "Service-specific deep content for every offering", "description": "Detailed pages covering each landscaping service — materials comparisons for patios, planting scheme options for different soil types, fence style guides, water feature installation processes — demonstrate expertise that generic competitors cannot match and capture long-tail search traffic."}, {"title": "Social media captions and project descriptions", "description": "AI generates engaging captions for your completed project photographs, seasonal tips for social media posting, and Google Business Profile updates. This content is tailored to your voice and brand, maintaining a consistent social presence without the time investment of writing from scratch."}]',
  '[{"question": "Will AI content sound authentic for a landscaping business?", "answer": "Yes. Our AI content system is trained on genuine horticultural knowledge, landscaping trade terminology, and your specific services and approach. Content references real plant species, actual materials and techniques, and Kent-specific growing conditions. Every piece is reviewed for accuracy before publication."}, {"question": "What types of content does the AI produce for landscapers?", "answer": "Blog posts covering seasonal topics, detailed service pages, project case study write-ups, social media captions for completed work, Google Business Profile posts, and email newsletter content. The system produces whatever content types deliver the most value for your specific marketing strategy."}, {"question": "How often will new content be published?", "answer": "We typically produce two to four blog posts per month plus ongoing social captions and service page updates. This frequency is enough to build meaningful search authority while maintaining quality. The exact volume is adjusted based on your competitive landscape and growth targets."}, {"question": "Do I need to review the content before it goes live?", "answer": "We recommend a brief review to ensure accuracy and alignment with your preferences. Most landscaping clients spend ten to fifteen minutes per week reviewing AI-generated content. We can also handle publication directly if you prefer a fully managed service."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;

-- 11. Landscapers × AI Automation
INSERT INTO public.industry_content (industry_slug, service_slug, intro_paragraph, why_needed, approach_difference, pain_points, solutions, faqs)
VALUES (
  'landscapers',
  'ai-automation',
  'AI automation for landscapers goes beyond simple email sequences — it introduces intelligent decision-making into your business operations. An AI system can analyse incoming enquiries and automatically route high-value garden design requests for priority follow-up while scheduling routine maintenance enquiries for batch processing. It can monitor weather forecasts and proactively notify affected customers about potential schedule changes before they chase you for updates. It can analyse your completed project photography, generate optimised descriptions, and post them to your social channels and Google Business Profile without manual intervention. For landscaping businesses handling dozens of enquiries, multiple active projects, and seasonal demand fluctuations simultaneously, AI automation transforms reactive firefighting into proactive, systematised operations. We build AI automation systems for landscapers that handle the intelligent admin tasks that currently consume your evenings and weekends.',
  'Landscaping businesses generate enormous amounts of repetitive administrative work — enquiry responses, quote preparation, scheduling coordination, customer updates, review collection, and seasonal marketing. As the business grows, this admin burden grows faster than revenue, forcing owners to choose between time on-site earning money and time at a desk managing operations. AI automation handles the intelligent repetitive tasks that currently bottleneck your growth.',
  'We build AI automations specific to landscaping workflows: intelligent enquiry triage that prioritises by project value, weather-aware schedule management that proactively communicates delays, automated project photography processing for social media, and smart seasonal campaign triggers based on local weather and calendar data.',
  '[{"title": "Evenings consumed by admin instead of rest or family", "description": "Landscaping business owners routinely spend two to three hours every evening processing enquiries, writing quotes, chasing approvals, and updating customers on project schedules. This unsustainable workload leads to burnout and forces a choice between business growth and personal wellbeing."}, {"title": "Weather disruptions creating communication chaos", "description": "Rain, frost, and wind regularly disrupt outdoor project schedules. Manually contacting every affected customer, rescheduling appointments, and coordinating revised timelines consumes hours of reactive admin that could be eliminated with proactive automated communication."}, {"title": "Growing enquiry volume impossible to manage manually", "description": "As marketing efforts increase enquiry flow, manually triaging, qualifying, and responding to every lead becomes unsustainable. High-value garden design enquiries get the same delayed response as simple hedge-trimming requests, and premium prospects hire the competitor who responded faster."}]',
  '[{"title": "Intelligent enquiry triage and priority routing", "description": "AI analyses incoming enquiries and automatically categorises them by project type, estimated value, and urgency. High-value garden design and hardscaping requests are flagged for immediate personal follow-up, while routine maintenance enquiries receive automated responses and scheduling — ensuring your time is spent on the most profitable conversations."}, {"title": "Weather-aware schedule management and customer communication", "description": "AI monitors local weather forecasts and automatically identifies projects likely to be affected by rain, frost, or high winds. Proactive notifications are sent to affected customers with revised timelines and rescheduling options, eliminating reactive communication and demonstrating professional project management."}, {"title": "Automated project content creation and distribution", "description": "When you upload completed project photos to a shared folder, AI generates optimised descriptions, creates before-and-after social media posts, updates your Google Business Profile, and adds the project to your website portfolio. A task that previously took thirty minutes per project happens automatically."}]',
  '[{"question": "How does AI triage landscaping enquiries?", "answer": "The AI analyses enquiry content for project indicators — garden size mentions, specific services requested, budget references, and timeline urgency. It assigns a priority score and routes high-value prospects for immediate personal response while sending automated acknowledgements and qualification questions to lower-priority enquiries."}, {"question": "Can AI automation handle weather-related schedule changes?", "answer": "Yes. The system monitors local weather forecasts and cross-references them with your project schedule. When weather is likely to affect outdoor work, it automatically notifies affected customers with delay explanations and rescheduling options, then updates your calendar when customers confirm new dates."}, {"question": "Will AI automation replace the personal touch with my customers?", "answer": "No. AI handles the repetitive administrative tasks — initial responses, qualification questions, scheduling logistics, review requests — freeing you to spend more personal time on site visits, design consultations, and the high-value interactions where your expertise and personality matter most."}, {"question": "What does AI automation cost for a landscaping business?", "answer": "AI automation systems are built to match your business scale and needs. Most landscaping businesses start with enquiry triage and quote follow-up automation, then expand to weather management and content distribution as they see results. The investment typically pays for itself within the first month through recovered leads and time savings."}]'
)
ON CONFLICT (industry_slug, service_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  why_needed = EXCLUDED.why_needed,
  approach_difference = EXCLUDED.approach_difference,
  pain_points = EXCLUDED.pain_points,
  solutions = EXCLUDED.solutions,
  faqs = EXCLUDED.faqs;
